import React from 'react';
import { Link } from 'react-router-dom';

export default function Header(){
  return (
    <header style={{background:'#222', color:'#fff', padding:10}}>
      <div style={{maxWidth:1000, margin:'0 auto'}}>
        <h1 style={{margin:0, fontSize:18}}>MusicPlayer</h1>
        <nav style={{marginTop:6}}>
          <Link to="/artistes" style={{color:'#9cf', marginRight:12}}>Artistes</Link>
          <Link to="/chansons" style={{color:'#9cf', marginRight:12}}>Chansons</Link>
          <Link to="/albums" style={{color:'#9cf', marginRight:12}}>Albums</Link>
        </nav>
      </div>
    </header>
  );
}
